SELECT COALESCE(SUM(amount), 0)
FROM flow_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}
  AND to_snapshot_id = #{assetSnapshotId}

SELECT COALESCE(SUM(amount),0)
FROM flow_template
WHERE user_id = #{userId}
  AND to_template_id = #{templateId}
